<?php
require_once __DIR__ . '/includes/auth.php';
$user=require_login(); $sessionId=(int)($_GET['session_id']??$_POST['session_id']??0); $reportedUserId=(int)($_GET['user_id']??$_POST['reported_user_id']??0); $session=null;
if($sessionId){$s=db()->prepare('SELECT id,title,host_id FROM study_sessions WHERE id=?');$s->execute([$sessionId]);$session=$s->fetch();if($session&&!$reportedUserId)$reportedUserId=(int)$session['host_id'];}
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$category=trim($_POST['category']??'');$details=trim($_POST['details']??'');if(!$category||strlen($details)<10){set_flash('error','Choose a reason and provide at least 10 characters of detail.');}else{db()->prepare('INSERT INTO reports (reporter_id,reported_user_id,session_id,category,details) VALUES (?,?,?,?,?)')->execute([(int)$user['id'],$reportedUserId?:null,$sessionId?:null,$category,$details]);set_flash('success','Your report was sent to the admin team.');redirect($sessionId?'session_details.php?id='.$sessionId:'home.php');}}
?>
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Submit report - StudyBuddy</title><script src="https://cdn.tailwindcss.com"></script><link href="https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700&family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet"><link rel="stylesheet" href="assets/css/style.css"></head><body><div class="min-h-screen flex items-center justify-center p-6"><main class="card p-7 max-w-lg w-full"><a href="<?=$sessionId?'session_details.php?id='.$sessionId:'home.php'?>" class="text-sm text-[var(--muted)]">← Go back</a><p class="text-xs font-semibold uppercase tracking-[.16em] text-[var(--coral)] mt-7">Safety report</p><h1 class="font-display text-2xl font-bold mt-1">Tell us what happened</h1><p class="text-sm text-[var(--muted)] mt-1 mb-6"><?=$session?'Reporting “'.e($session['title']).'”.':'An administrator will review your report.'?></p><?php render_flashes()?><form method="POST" class="space-y-5"><?=csrf_field()?><input type="hidden" name="session_id" value="<?=$sessionId?>"><input type="hidden" name="reported_user_id" value="<?=$reportedUserId?>"><div class="field"><label>Reason</label><select name="category" required><option value="">Choose a reason</option><option>Harassment or bullying</option><option>Spam or misleading content</option><option>Unsafe behavior</option><option>Inappropriate session</option><option>Fake account</option><option>Other concern</option></select></div><div class="field"><label>Details</label><textarea name="details" required minlength="10" placeholder="Describe what happened and include helpful context."></textarea></div><p class="text-xs text-[var(--muted)]">Reports are private and visible only to administrators.</p><button class="btn-dark w-full">Submit report</button></form></main></div></body></html>
